1803     // Move instructions from the guard block of FC1 to the end of the guard
1804     // block of FC0.
1805     moveInstructionsToTheEnd(*FC1GuardBlock, *FC0GuardBlock, DT, PDT, DI);
1806 
1807     assert(FC0NonLoopBlock == FC1GuardBlock && "Loops are not adjacent");
