1830         DominatorTree::Delete, FC1GuardBlock, FC1.Preheader));
1831     TreeUpdates.emplace_back(DominatorTree::UpdateType(
1832         DominatorTree::Delete, FC1GuardBlock, FC1NonLoopBlock));
